def route(event, rules, default="unrouted"):
    priority = event.get("priority", 0)
    matching_rules = []
    for rule in rules:
        if event.get("kind") == rule["kind"] and priority >= rule.get("min_priority", 0):
            matching_rules.append(rule)

    if not matching_rules:
        return default

    # Sort by min_priority descending (most specific first)
    # Stable sort preserves input order for ties
    matching_rules.sort(key=lambda r: r.get("min_priority", 0), reverse=True)
    return matching_rules[0]["target"]

